INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8a120c9e-ee9e-4828-9ff5-075ce654c4ef',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets — Connection Lifecycle, Heartbeat, Reconnection, and Rooms$escape$,
  $escape$A WebSocket connection transitions through four readyStates: CONNECTING (0), OPEN (1), CLOSING (2), CLOSED (3). Most bugs come from writing to a socket before it's OPEN or after the server has already closed it — always guard sends with `if (ws.readyState === WebSocket.OPEN)`.

Heartbeats keep NAT gateways and load balancers from silently dropping idle connections. The standard pattern: client sends a `ping` message every 30s, server echoes a `pong`. If no pong arrives within a timeout window, treat the connection as dead and trigger reconnect.

Reconnection should use exponential backoff with jitter — reconnecting 1000 clients simultaneously after a server restart creates a thundering herd. Cap backoff at ~30s and add `Math.random() * 1000` ms of jitter.

Rooms are a server-side abstraction: a `Map<string, Set<WebSocket>>` keyed by room ID. On message, iterate the room's set and call `client.send()` only if `client.readyState === WebSocket.OPEN`. Crucially, remove clients from all rooms inside the `ws.on('close', ...)` handler to prevent memory leaks and phantom broadcasts.$escape$,
  $escape$const rooms = new Map<string, Set<WebSocket>>();

function joinRoom(roomId: string, ws: WebSocket) {
  if (!rooms.has(roomId)) rooms.set(roomId, new Set());
  rooms.get(roomId)!.add(ws);
}

function broadcast(roomId: string, message: string, sender: WebSocket) {
  rooms.get(roomId)?.forEach(client => {
    if (client !== sender && client.readyState === WebSocket.OPEN)
      client.send(message);
  });
}

ws.on('close', () => {
  rooms.forEach(members => members.delete(ws));
});

// Heartbeat
const interval = setInterval(() => {
  if (ws.readyState === WebSocket.OPEN) ws.send(JSON.stringify({ type: 'ping' }));
}, 30_000);$escape$,
  $escape$typescript$escape$,
