INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a438e64a-cddf-4208-afbf-1f617871872e',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets + tRPC — Type-Safe Subscriptions with React Query$escape$,
  $escape$tRPC's `subscription` procedure type maps directly to a persistent WebSocket connection via `@trpc/server/adapters/ws`. On the server, a subscription returns an `observable<T>`, and the WS adapter keeps that stream open over a single WebSocket frame channel — no SSE fallback, no polling. The client uses `createWSClient` paired with `wsLink`, typically composed with `splitLink` to route queries/mutations over HTTP and subscriptions over the WebSocket. This split is critical: HTTP procedures get batching and caching; subscriptions get the low-latency bidirectional channel they need. On the React side, `trpc.[procedure].useSubscription()` integrates directly with React Query's cache — incoming WebSocket messages can call `utils.[procedure].setData()` to invalidate or patch cached query state. The full type chain — from `observable<OutputType>` on the server to the inferred hook return on the client — is preserved end-to-end without codegen. Reconnect logic, including exponential backoff, is handled by `createWSClient`'s `retryDelay` option.$escape$,
  $escape$// server.ts
const appRouter = router({
  onStockTick: publicProcedure
    .input(z.object({ symbol: z.string() }))
    .subscription(({ input }) =>
      observable<{ price: number }>(({ next }) => {
        const unsub = stockFeed.on(input.symbol, next);
        return () => unsub();
      })
    ),
});

// client.ts
const wsClient = createWSClient({ url: 'ws://localhost:3001', retryDelay: () => 1000 });
const trpc = createTRPCReact<AppRouter>();
const client = trpc.createClient({
  links: [
    splitLink({
      condition: (op) => op.type === 'subscription',
      true: wsLink({ client: wsClient }),
      false: httpBatchLink({ url: '/api/trpc' }),
    }),
  ],
});

// component.tsx
trpc.onStockTick.useSubscription({ symbol: 'AAPL' }, {
  onData: (tick) => utils.stockSnapshot.setData({ symbol: 'AAPL' }, (prev) => ({ ...prev, price: tick.price })),
});$escape$,
