INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3d800c95-1ce3-4123-a2a8-dc5ce1a48fd1',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets Protocol Design — REST Semantics in a Persistent Connection$escape$,
  $escape$WebSocket connections are stateful and long-lived — there are no per-message HTTP verbs or status codes baked in. But REST semantics still belong in your protocol design. The connection URL is your only shot at resource naming: `wss://api.example.com/feeds/{userId}` — keep it noun-based and hierarchical, not action-driven (`/connectFeed` is a REST anti-pattern that's even worse here).

Embed an `action` field in every message envelope — `subscribe`, `unsubscribe`, `publish`, `ack`. These map loosely to POST, DELETE, PUT, and a WebSocket-specific acknowledgement that REST doesn't need. For status, use WebSocket close codes (1000–1015 spec-defined, 4000–4999 application-defined) at the connection level, and mirror HTTP status semantics inside message payloads: `{ status: 404, error: "channel.not_found" }`.

Idempotency matters most on reconnect. Every outbound message should carry a `messageId`. On reconnect, replay unacknowledged messages — but the server must deduplicate by `messageId` to prevent double-processing. A Redis SET with a short TTL is the standard guard. Without this structure, your WebSocket API degrades into an untyped event bus that's impossible to audit, replay, or version.$escape$,
  $escape$interface WsEnvelope {
  messageId: string;
  action: "subscribe" | "publish" | "ack" | "unsubscribe";
  resource: string; // e.g. "/feeds/user-123"
  status?: number;
}
const seen = new Set<string>();
ws.on("message", (raw: string) => {
  const msg: WsEnvelope = JSON.parse(raw);
  if (seen.has(msg.messageId)) return; // idempotency guard
  seen.add(msg.messageId);
  if (msg.action === "subscribe") {
    ws.send(JSON.stringify({ messageId: crypto.randomUUID(), status: 200, action: "ack", resource: msg.resource }));
  }
});$escape$,
