INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '17edbeaf-d794-4b18-afd8-c7af11d8bb2d',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets + GraphQL Subscriptions — Per-Event DataLoader Scoping and N+1 in Real-Time Resolvers$escape$,
  $escape$GraphQL subscriptions run over persistent WebSocket connections using the `graphql-ws` protocol (the modern successor to `subscriptions-transport-ws`). Each subscription resolver returns an `AsyncIterator` — when PubSub emits, every subscribed client's field resolvers fire against that payload independently.

N+1 behaves differently here than in HTTP queries. In a standard query, DataLoader batches within a single request tick. In subscriptions, each emitted event is its own execution context. If you scope DataLoader to the connection — `context()` firing once on `connection_init` — the loader cache goes stale across events, silently serving outdated data. You must scope a fresh DataLoader instance per-execution, not per-connection.

`graphql-ws`'s `context` callback receives `(ctx, message, args)`: the third argument signals an active operation execution, making it the right place to instantiate loaders. This gives you per-event batching without cross-event cache poisoning.

On schema design: avoid subscriptions that return only an ID and force clients to re-fetch over HTTP. Resolve the full type server-side and push it over the wire — one WebSocket frame replaces N round-trips per subscriber.$escape$,
  $escape$import { useServer } from 'graphql-ws/lib/use/ws';
import { WebSocketServer } from 'ws';
import DataLoader from 'dataloader';

useServer({
  schema,
  // context() with 3 args = per-execution scope (not per-connection)
  context: async (_ctx, _msg, args) => {
    if (!args) return {}; // connection_init — no loader needed yet
    return {
      userLoader: new DataLoader((ids: readonly string[]) => batchLoadUsers(ids)),
    };
  },
}, new WebSocketServer({ port: 4000 }));

// Batches all sibling `author` lookups within a single emitted event tick
const MessageResolver = {
  author: ({ authorId }: { authorId: string }, _: unknown, { userLoader }: Ctx) =>
    userLoader.load(authorId),
};$escape$,
  $escape$typescript$escape$,
