INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c3eb3c31-f396-468e-b052-cad2be3c2742',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets Rate Limiting — Sliding Window vs Token Bucket Per Connection$escape$,
  $escape$Unlike HTTP, WebSocket connections are long-lived — a single socket can flood your server with thousands of frames per second. Rate limiting must happen at the message frame level, not just connection establishment.

Two practical strategies: **sliding window** tracks message timestamps in a rolling buffer (e.g., max 100 messages per 10s). It's precise but memory-intensive per connection. **Token bucket** grants each socket a bucket of tokens that refill at a fixed rate — burst-friendly and O(1) per message check.

For per-user limiting across multiple sockets (same user, multiple tabs), store state in Redis using the user's sub claim from the upgrade handshake JWT. Key pattern: `rl:{userId}:{endpoint}` — where endpoint maps to your message `type` field, not an HTTP route.

On violation, don't close the socket with `ws.terminate()` — that's abrupt. Send a typed control frame (`{ type: 'rate_limit_exceeded', retryAfter: 3000 }`) then call `ws.close(1008, 'Policy Violation')` with the correct WebSocket close code. Clients can back off gracefully using the `retryAfter` value.$escape$,
  $escape$// Token bucket per WebSocket connection (ws + ws library)
const buckets = new Map<WebSocket, { tokens: number; lastRefill: number }>();

const RATE = 10; // tokens per second
const CAPACITY = 30;

function consume(ws: WebSocket): boolean {
  const now = Date.now();
  const bucket = buckets.get(ws) ?? { tokens: CAPACITY, lastRefill: now };
  const elapsed = (now - bucket.lastRefill) / 1000;
  bucket.tokens = Math.min(CAPACITY, bucket.tokens + elapsed * RATE);
  bucket.lastRefill = now;
  if (bucket.tokens < 1) return false;
  bucket.tokens -= 1;
  buckets.set(ws, bucket);
  return true;
}

wss.on('connection', (ws) => {
  ws.on('message', (raw) => {
    if (!consume(ws)) {
      ws.send(JSON.stringify({ type: 'rate_limit_exceeded', retryAfter: 1000 }));
      return;
    }
    // handle message
  });
  ws.on('close', () => buckets.delete(ws));
});$escape$,
