INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2fb70a1a-972f-4bc8-9b58-cd5003a7b11e',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets Pagination — Why Offsets Break Real-Time Feeds and How to Fix It$escape$,
  $escape$Offset-based pagination collapses in WebSocket-driven feeds. If your server pushes 10 new messages while a client is scrolling, `FETCH_PAGE offset=20` silently skips or duplicates items — there are no HTTP headers to signal this shift. Cursor pagination solves this: anchor each page request to a stable `last_id` or ISO timestamp from the final item the client received.

Since WebSockets have no built-in pagination semantics, all metadata travels inside your message payload. Avoid returning `total_count` — it's stale the moment the server emits it and forces an expensive `COUNT(*)`. Instead, return a `has_more: boolean` derived from fetching `limit + 1` rows.

For infinite scroll, the client tracks `next_cursor` in memory. On a scroll threshold event, it sends a `FETCH_MORE` frame. The server streams back a `PAGE` frame with the next slice and an updated cursor. If the connection drops mid-scroll, reconnect logic can resume from the last known cursor without re-fetching from the top — a guarantee offset can never provide in a live stream.$escape$,
  $escape$// Client-side infinite scroll over a persistent WebSocket
const ws = new WebSocket('wss://api.byteai.dev/feed');
let nextCursor: string | null = null;

function fetchMore() {
  ws.send(JSON.stringify({ type: 'FETCH_MORE', cursor: nextCursor, limit: 20 }));
}

ws.onmessage = (event) => {
  const { type, data, next_cursor, has_more } = JSON.parse(event.data);
  if (type === 'PAGE') {
    renderItems(data);
    nextCursor = next_cursor;
    if (!has_more) detachScrollListener();
  }
};

fetchMore(); // initial load$escape$,
  $escape$typescript$escape$,
