INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '91f8a0a4-10c6-4283-abf8-a60bf009e90b',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets Error Handling — Structured Errors Without HTTP's Problem+JSON$escape$,
  $escape$WebSockets lack HTTP status codes, so ad-hoc error strings leak into client logic fast. The fix: mirror RFC 9457 Problem+JSON inside every message payload. Define a typed envelope where every frame — success or failure — carries a `type` discriminant. On error, include `type: 'error'`, a `code` (machine-readable, namespaced like `ws://errors/rate-limited`), a human `detail`, and optional `extensions` for domain data. Close frames use WebSocket close codes (1008 for policy violation, 1011 for internal error), but these are coarse-grained — the structured payload carries the real diagnostic. On the server, catch all handler errors at the message-dispatch layer and serialize them into this envelope before writing to the socket. Never let unhandled rejections silently close the connection with code 1006 (abnormal closure), which gives clients zero context. Clients pattern-match on `msg.code` for retry logic, user messaging, and telemetry. This keeps your WebSocket protocol as self-documenting as a REST API.$escape$,
  $escape$// server: Node.js ws library
wss.on('connection', (socket) => {
  socket.on('message', async (raw) => {
    try {
      const msg = JSON.parse(raw.toString());
      const result = await dispatch(msg);
      socket.send(JSON.stringify({ type: 'success', data: result }));
    } catch (err) {
      socket.send(JSON.stringify({
        type: 'error',
        code: err.code ?? 'ws://errors/internal',
        detail: err.message,
        extensions: err.meta ?? {},
      }));
    }
  });
});$escape$,
  $escape$javascript$escape$,
