INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c82ee7cf-7341-4be9-80e3-3feac9e0bf9f',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets Authentication — JWT, API Keys, and mTLS at the Upgrade Boundary$escape$,
  $escape$WebSocket authentication must happen at the HTTP upgrade handshake — once the connection is established, there's no in-band re-auth mechanism without a full reconnect. This constraint shapes every auth pattern.

Browsers can't set custom headers on WebSocket connections, so passing a JWT in an Authorization header is impossible from the browser. The two practical alternatives: encode the token as a Sec-WebSocket-Protocol subprotocol value (client sends `new WebSocket(url, ['jwt.eyJ...'])`), or use first-message auth where the server holds the socket in an unauthenticated state for a short TTL, then drops it if no valid token arrives.

Query string tokens (`?token=xxx`) are the worst option — they appear in access logs, Nginx/Cloudflare caches, and browser history. Treat them as plaintext.

For API keys in service-to-service scenarios, the Sec-WebSocket-Protocol trick works identically. For mTLS, client certificates are validated at TLS termination before the HTTP upgrade fires — zero token management, no replay risk, ideal for backend WebSocket services behind a sidecar or API gateway.

Always set a connection timeout on unauthenticated sockets. An open, unauthenticated WebSocket is a resource leak waiting to be exploited.$escape$,
  $escape$import { WebSocketServer } from 'ws';
import { verify } from 'jsonwebtoken';
import type { IncomingMessage } from 'http';

const wss = new WebSocketServer({
  port: 8080,
  verifyClient: ({ req }: { req: IncomingMessage }, done) => {
    const protocols = (req.headers['sec-websocket-protocol'] ?? '')
      .split(',').map(s => s.trim());
    const token = protocols.find(p => p.startsWith('jwt.'))?.slice(4);

    if (!token) return done(false, 401, 'Missing token');
    try {
      verify(token, process.env.JWT_SECRET!);
      done(true);
    } catch {
      done(false, 401, 'Invalid token');
    }
  },
});

// Client: new WebSocket('wss://host/ws', [`jwt.${accessToken}`])$escape$,
