INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9e102c3f-e9ed-4604-9619-e3c7787007bd',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSocket Security — CSRF, Input Validation, and Injection Risks You're Probably Missing$escape$,
  $escape$WebSocket handshakes use HTTP, which means CSRF is real: browsers send cookies automatically during the upgrade request. Validate the `Origin` header server-side on every upgrade — reject anything not in your allowlist. This is your only CSRF defense since WebSockets ignore CORS preflight.

Once the connection is established, every `message` event is an untrusted input boundary. Clients control the payload entirely — parse and validate before acting. If you're framing messages as JSON-RPC or GraphQL over WebSocket, treat each `type` field as an injection vector. A client sending `{"type":"__schema"}` can trigger full GraphQL introspection if your resolver doesn't gate it behind auth checks at the subscription layer, not just at the HTTP endpoint.

For text payloads destined for SQL or shell commands, standard injection rules apply but are easier to miss since WebSocket handlers often lack the middleware chain that HTTP routes have. Apply parameterized queries and schema validation (e.g., Zod, Joi, or JSON Schema) explicitly in your message handler — don't assume upstream middleware ran.$escape$,
  $escape$import { WebSocketServer } from 'ws';
import { z } from 'zod';

const ALLOWED_ORIGINS = new Set(['https://app.example.com']);

const MessageSchema = z.object({
  type: z.enum(['subscribe', 'unsubscribe', 'ping']),
  channel: z.string().max(64).regex(/^[a-zA-Z0-9_-]+$/),
});

const wss = new WebSocketServer({ noServer: true });

server.on('upgrade', (req, socket, head) => {
  const origin = req.headers['origin'];
  if (!ALLOWED_ORIGINS.has(origin)) {
    socket.write('HTTP/1.1 403 Forbidden\r\n\r\n');
    socket.destroy();
    return;
  }
  wss.handleUpgrade(req, socket, head, (ws) => wss.emit('connection', ws, req));
});

wss.on('connection', (ws) => {
  ws.on('message', (raw) => {
    const parsed = MessageSchema.safeParse(JSON.parse(raw.toString()));
    if (!parsed.success) { ws.close(1008, 'Invalid payload'); return; }
    // safe to handle parsed.data
  });
});$escape$,
  $escape$javascript$escape$,
