INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5f0389d0-a063-4759-86b0-a06ab5842def',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets Testing — Contract Tests, Mocks, and Integration Strategies$escape$,
  $escape$Testing WebSocket servers requires a three-layer approach. Contract tests lock down your message schema: define a JSON Schema (or Zod schema) for every event type — `chat.message`, `presence.update`, `error` — and validate both directions. Run these against a real server in CI so client and server never drift. For unit tests, mock the WebSocket at the `ws.send` / `ws.on` boundary using a lightweight EventEmitter shim; avoid mocking `net.Socket` or `uWebSockets` internals. For integration tests, spin up a real `ws.WebSocketServer` on a random port, connect a `WebSocket` client, and assert on received frames directly. Use `ws.readyState === WebSocket.OPEN` guards and promisify `close` events to avoid flaky teardowns. Test reconnection logic by forcibly destroying the underlying socket (`socket.destroy()`), not by calling `ws.close()`, which performs a clean handshake — that masks real reconnect bugs. Validate ping/pong heartbeat cycles independently: assert `ws.on('pong')` fires within your configured interval before the server terminates idle connections.$escape$,
  $escape$import { WebSocketServer, WebSocket } from 'ws';
import { AddressInfo } from 'net';

let wss: WebSocketServer;
let client: WebSocket;

beforeEach((done) => {
  wss = new WebSocketServer({ port: 0 });
  const { port } = wss.address() as AddressInfo;
  client = new WebSocket(`ws://localhost:${port}`);
  client.once('open', done);
});

afterEach((done) => {
  client.close();
  wss.close(done);
});

test('echoes message back to client', (done) => {
  wss.on('connection', (socket) => {
    socket.on('message', (data) => socket.send(data));
  });
  client.send(JSON.stringify({ type: 'ping' }));
  client.once('message', (data) => {
    expect(JSON.parse(data.toString())).toEqual({ type: 'ping' });
    done();
  });
});$escape$,
