INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '82a0405e-c15a-40bf-a36f-76a1dc7cc05b',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets Idempotency — Surviving Reconnects Without Duplicate Mutations$escape$,
  $escape$WebSocket connections are stateful and persistent, but delivery is not guaranteed. When a client sends a mutating frame — say, `place_order` — and the connection drops before an acknowledgment arrives, the client must decide: resend or not? Without idempotency, resending creates duplicates.

Unlike HTTP, WebSocket messages carry no method semantics. There's no built-in distinction between "safe" (read-only) and "idempotent" (repeatable) operations — your application protocol must define these. Query-style messages like `get_feed` are naturally idempotent; mutations like `submit_post` or `transfer_funds` are not.

The fix: attach a `messageId` (UUID v4) to every mutating frame. The server caches processed IDs in Redis or an in-memory TTL store. On receiving a message, check the cache first — if the ID exists, return the cached response without re-executing the mutation.

Set TTL to match your client retry window (typically 30–60 s). This gives you exactly-once semantics over an at-least-once transport, making your WebSocket API safe to replay across reconnects without corrupting state.$escape$,
  $escape$// Client — stamp every mutating message with a stable idempotency key
function send(ws: WebSocket, type: string, payload: unknown) {
  const msg = { id: crypto.randomUUID(), type, payload };
  ws.send(JSON.stringify(msg));
  return msg.id;
}

// Server (ws library) — deduplicate within a TTL window
const seen = new Map<string, { result: unknown; expiresAt: number }>();

wss.on('connection', (ws) => {
  ws.on('message', (raw) => {
    const { id, type, payload } = JSON.parse(raw.toString());
    const cached = seen.get(id);
    if (cached && cached.expiresAt > Date.now())
      return ws.send(JSON.stringify({ id, status: 'duplicate', result: cached.result }));
    const result = handleMutation(type, payload);
    seen.set(id, { result, expiresAt: Date.now() + 60_000 });
    ws.send(JSON.stringify({ id, status: 'ok', result }));
  });
});$escape$,
