INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '76a11115-5d0a-46ed-bed2-510a4d898d30',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets and HTTP Caching — Why the Split-Hydration Pattern Wins$escape$,
  $escape$WebSocket frames carry zero HTTP caching semantics. There is no Cache-Control, ETag, or CDN layer once the connection is upgraded — every frame is a raw binary or text payload delivered directly to your `onmessage` handler. This makes initial-state hydration the critical problem: clients reconnecting after a drop shouldn't re-stream megabytes the server already sent.

The pattern: serve your state snapshot over a cacheable HTTP endpoint with strong ETags. On connect (or reconnect), the client issues a conditional GET with `If-None-Match`. A 304 means the snapshot hasn't changed — skip the refetch, reuse the cached payload, then open the WebSocket immediately. A 200 means state diverged; update local cache before subscribing.

CDNs like Cloudflare and AWS CloudFront will proxy the WebSocket upgrade (`Connection: Upgrade`, `Upgrade: websocket` headers must pass through), but they cache zero frames. Configure HTTP cache aggressively on the snapshot route while leaving the WebSocket path untouched. This split — cached snapshot + live delta stream — slashes reconnect latency and eliminates thundering-herd refetches when thousands of clients simultaneously drop.$escape$,
  $escape$const etag = sessionStorage.getItem('feed-etag');
const res = await fetch('/api/feed/snapshot', {
  headers: etag ? { 'If-None-Match': etag } : {}
});

let snapshot: FeedState;
if (res.status === 200) {
  snapshot = await res.json();
  sessionStorage.setItem('feed-etag', res.headers.get('ETag') ?? '');
  sessionStorage.setItem('feed-snapshot', JSON.stringify(snapshot));
} else {
  snapshot = JSON.parse(sessionStorage.getItem('feed-snapshot') ?? '{}');
}

const ws = new WebSocket('wss://api.example.com/feed/live');
ws.onmessage = ({ data }) => applyDelta(snapshot, JSON.parse(data) as FeedDelta);$escape$,
  $escape$typescript$escape$,
