INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bbaac26c-7420-4be5-9901-b51c1d5268e4',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets Performance — Compression, Binary Frames, and Application-Layer Multiplexing$escape$,
  $escape$WebSockets give you a persistent TCP connection, but performance isn't automatic. Three levers matter.

**Compression:** Enable `permessage-deflate` via `perMessageDeflate` in the `ws` library. It shares an LZ77 sliding window across frames, but the default `serverMaxWindowBits: 15` allocates 32 KB per connection. On high-concurrency servers, drop it to 10–12 — you trade ~15% compression ratio for 97% less memory per socket. Set `threshold: 128` to skip deflate on small control frames entirely.

**Payload format:** JSON costs you UTF-8 validation on every text frame. Switch to MessagePack or CBOR and send `Buffer` or `Uint8Array` — binary frames skip that validation step in the WebSocket framing layer and typically run 30–40% smaller on structured data.

**Multiplexing:** WebSockets have no native stream multiplexing — unlike HTTP/2, one connection is one ordered queue. For concurrent request/response patterns, embed a correlation `id` in every message envelope and dispatch responses by ID at the application layer. Never open multiple sockets per client to fake parallelism; you'll exhaust file descriptors before you exhaust CPU.$escape$,
  $escape$import { WebSocketServer } from 'ws';
import { pack, unpack } from 'msgpackr';

const wss = new WebSocketServer({
  port: 8080,
  perMessageDeflate: {
    serverMaxWindowBits: 10,  // 1 KB vs default 32 KB per connection
    clientMaxWindowBits: 10,
    threshold: 128,           // skip deflate for frames under 128 bytes
  },
});

wss.on('connection', (ws) => {
  ws.on('message', (raw) => {
    const msg = unpack(raw as Buffer);              // ~35% smaller than JSON
    ws.send(pack({ id: msg.id, result: handle(msg) })); // binary frame, no UTF-8 cost
  });
});$escape$,
