INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1bce6f30-6754-4505-8630-0c5ce1538e80',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebSockets vs REST vs GraphQL vs gRPC — A Decision Framework for Real-Time Engineers$escape$,
  $escape$WebSockets give you full-duplex, persistent TCP connections — but that's overkill for most API interactions. Here's how to decide.

Use WebSockets when your server needs to push unsolicited events to a browser client and the client talks back: live dashboards, multiplayer games, collaborative editors. The `ws.send()` / `ws.onmessage` loop is your primitive.

Use REST for stateless CRUD where the client drives every interaction. No persistent connection overhead, HTTP caching works, and your load balancer doesn't need sticky sessions.

Use GraphQL when clients need flexible data shapes plus occasional real-time updates. GraphQL Subscriptions tunnel over WebSockets via `graphql-ws`, so you're using WebSockets under the hood — just with a schema contract enforcing message shape.

Use gRPC for service-to-service streaming where you want HTTP/2 multiplexing, Protobuf-typed contracts, and bidirectional streaming without managing raw WebSocket frames. gRPC streams are HTTP/2 streams — you get built-in flow control and header compression that the WebSocket protocol leaves to you.

The deciding signal: unsolicited server push to a browser → WebSockets. Typed service mesh streaming → gRPC. Flexible queries + subscriptions → GraphQL over WebSockets. Stateless CRUD → REST.$escape$,
  $escape$// WebSockets: raw bidirectional, browser-native
const ws = new WebSocket('wss://api.example.com/live');
ws.onmessage = ({ data }) => console.log('push:', JSON.parse(data));
ws.send(JSON.stringify({ type: 'subscribe', channel: 'trades' }));

// GraphQL Subscriptions — WebSockets under the hood via graphql-ws
import { createClient } from 'graphql-ws';
const gqlClient = createClient({ url: 'wss://api.example.com/graphql' });
gqlClient.subscribe(
  { query: `subscription { tradeCreated { id price symbol } }` },
  { next: ({ data }) => console.log('gql push:', data) }
);

// gRPC bidirectional stream — HTTP/2, NOT a WebSocket
const stream = grpcClient.tradeStream();
stream.on('data', (chunk) => console.log('gRPC push:', chunk));
stream.write({ symbol: 'AAPL' });$escape$,
